          },
          "briefTitle": "Sonazoid Contrast-enhanced Ultrasound in Assessing Effectiveness of Neoadjuvant Chemotherapy in Breast Cancer Patients.",
          "officialTitle": "Sonazoid Contrast-enhanced Ultrasound in Assessing Effectiveness of Neoadjuvant Chemotherapy in Breast Cancer Patients."
        },
        "statusModule": {
          "statusVerifiedDate": "2020-12",
          "overallStatus": "UNKNOWN",
          "lastKnownStatus": "ACTIVE_NOT_RECRUITING",
          "expandedAccessInfo": {
            "hasExpandedAccess": false
          },
          "startDateStruct": {
            "date": "2020-08-01",
            "type": "ACTUAL"
          },
          "primaryCompletionDateStruct": {
            "date": "2021-03",
            "type": "ESTIMATED"
          },
          "completionDateStruct": {
            "date": "2021-12",
            "type": "ESTIMATED"
          },
          "studyFirstSubmitDate": "2020-09-26",
          "studyFirstSubmitQcDate": "2020-12-05",
          "studyFirstPostDateStruct": {
            "date": "2020-12-08",
            "type": "ACTUAL"
          },
          "lastUpdateSubmitDate": "2020-12-05",
          "lastUpdatePostDateStruct": {
            "date": "2020-12-08",
            "type": "ACTUAL"
          }
        },
        "sponsorCollaboratorsModule": {
          "responsibleParty": {
            "type": "PRINCIPAL_INVESTIGATOR",
            "investigatorFullName": "Ping Liang",
            "investigatorTitle": "Chief physician",
            "investigatorAffiliation": "Chinese PLA General Hospital"
          },
          "leadSponsor": {
            "name": "Chinese PLA General Hospital",
            "class": "OTHER"
          }
        },
        "oversightModule": {
          "oversightHasDmc": false,
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": false
        },
        "descriptionModule": {
          "briefSummary": "Sonazoid as a new generation of ultrasound contrast agent.This study based on the features of Sonazoid specific angiography and high mechanical index,the role of Sonazoid in assessing effectiveness of neoadjuvant chemotherapy in breast cancer patients was explored.",
          "detailedDescription": "This is a prospective, multicenter study.More than 1000 participants will enrolled.Most of them with CEUS,MRI and pathological follow up.When enhanced MRI is needed in the neoadjuvant cycle of patients, Sonazoid-CEUS examination is added at this time point, and postoperative pathology will be used as the gold standard, so as to compare the ability of the two imaging examinations in judging the effect of neoadjuvant chemotherapy.\n\nInvestigators will also record the parameter information of imaging examination, pathological type of pathological examination and immunohistochemical index, etc.Contrast-enhanced ultrasound includes lesion location, initial peak tumor volume, 1-minute tumor volume, 2-minute tumor volume, and 5-minute tumor volume, as well as the time for contrast enhancement, contrast agent clearance, and contrast agent clearance.Whether there is no enhancement area in the lesion after contrast enhancement, shape after contrast enhancement, edge after contrast enhancement, order of enhancement, uniformity of enhancement, intensity enhancement, pattern of enhancement, clear boundary after contrast enhancement, aspect ratio after contrast enhancement, etc.The magnetic field strength of the equipment is planned to be recorded in the enhanced MRI information, the name of the MRI contrast agent, the lesion location, the size of the lesion, and the scanning performance are enhanced (lump-like enhancement, non-lump-like enhancement, point-like enhancement), time-signal intensity enhancement curve, DWI signal, ADC value, etc."
        },
        "conditionsModule": {
          "conditions": [
            "Ultrasound"
          ],
          "keywords": [
            "breast"
          ]
        },
        "designModule": {
          "studyType": "OBSERVATIONAL",
          "patientRegistry": false,
          "designInfo": {
            "observationalModel": "OTHER",
            "timePerspective": "PROSPECTIVE"
          },
          "enrollmentInfo": {
            "count": 1012,
            "type": "ESTIMATED"
          }
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Sonazoid contrast-enhanced ultrasound in assessing effectiveness of neoadjuvant chemotherapy in breast cancer patients.",
              "description": "Pathology as a gold standard,to compare the diagnostic performance between contrast-enhanced ultrasound and other contrast-enhanced imaging in neoadjuvant chemotherapy in breast cancer patients.",
              "timeFrame": "10 months"
            }
          ]
        },
        "eligibilityModule": {
          "eligibilityCriteria": "Inclusion Criteria:\n\n* (1) Refer to the guidelines and specifications for diagnosis and treatment of breast cancer, and it is clearly identified as breast cancer by pathological biopsy.\n* (2) Plan to implement NAC therapy;\n* (3) All patients and their family members signed informed consent forms, which were approved by the hospital medical Ethics Committee\n\nExclusion Criteria:\n\n* (1) Those who are known to be allergic to ultrasound contrast agents;\n* (2)The subject has a history of allergy to eggs or egg products (i.e. skin rash, dyspnea, swelling of the mouth or throat, hypotension or shock, etc.)\n* (3) Intolerance to neoadjuvant chemotherapy;\n* (4) Poor compliance with chemotherapy treatment;\n* (5) Patients who cannot receive contrast agent MRI examination\n* (6) Arteriovenous (left and right) shunt patients in the heart and lungs;\n* (7) Mental disorders or mental disorders;\n* (8)Patients with serious heart disease or lung disease;\n* (9)Pet-pregnant, possibly pregnant or lactating;\n* (10)In addition, the researcher or the researcher thinks that the patient is not suitable to participate in this study.",
          "healthyVolunteers": false,
          "sex": "FEMALE",
          "minimumAge": "18 Years",
          "maximumAge": "85 Years",
          "stdAges": [
            "ADULT",
            "OLDER_ADULT"
          ],
          "studyPopulation": "Breast cancer patients who plan neoadjuvant chemotherapy and conform to contrast-enhanced ultrasound, enhanced mri, and surgical indications.",
          "samplingMethod": "PROBABILITY_SAMPLE"
        },
        "contactsLocationsModule": {
          "overallOfficials": [
            {
              "name": "Ping Liang, Doctor",
              "affiliation": "Chinese PLA General Hospital",
              "role": "PRINCIPAL_INVESTIGATOR"
            }
          ],
          "locations": [
            {
              "facility": "Chinese PLA General Hospital",
              "city": "Beijing",
              "state": "Beijing Municipality",
              "zip": "100853",
              "country": "China",
              "geoPoint": {
                "lat": 39.9075,
                "lon": 116.39723
              }
            }
          ]
        }
      },
