  "totalCount": 1013,
  "studies": [
    {
      "protocolSection": {
        "identificationModule": {
          "nctId": "NCT06130241",
          "orgStudyIdInfo": {
            "id": "sentinel L.N in breast cancer"
          },
          "organization": {
            "fullName": "Assiut University",
