          },
          "briefTitle": "Sentinel Lymph Node Biopsy After Neoadjuvant Chemotherapy in Initially Node Positive Breast Cancer Patients, Could it Omit Axillary Dissection ?",
          "officialTitle": "Sentinel Lymph Node Biopsy After Neoadjuvant Chemotherapy in Initially Node Positive Breast Cancer Patients, Could it Omit Axillary Dissection ?"
        },
        "statusModule": {
          "statusVerifiedDate": "2023-11",
          "overallStatus": "UNKNOWN",
          "lastKnownStatus": "NOT_YET_RECRUITING",
          "expandedAccessInfo": {
            "hasExpandedAccess": false
          },
          "startDateStruct": {
            "date": "2023-11-30",
            "type": "ESTIMATED"
          },
          "primaryCompletionDateStruct": {
            "date": "2025-01-01",
            "type": "ESTIMATED"
          },
          "completionDateStruct": {
            "date": "2025-04-01",
            "type": "ESTIMATED"
          },
          "studyFirstSubmitDate": "2023-11-08",
          "studyFirstSubmitQcDate": "2023-11-11",
          "studyFirstPostDateStruct": {
            "date": "2023-11-14",
            "type": "ACTUAL"
          },
          "lastUpdateSubmitDate": "2023-11-11",
          "lastUpdatePostDateStruct": {
            "date": "2023-11-14",
            "type": "ACTUAL"
          }
        },
        "sponsorCollaboratorsModule": {
          "responsibleParty": {
            "type": "PRINCIPAL_INVESTIGATOR",
            "investigatorFullName": "Mohamed Hosny Mahmoud",
            "investigatorTitle": "Resident doctor at general surgery department in Assuit university hospital",
            "investigatorAffiliation": "Assiut University"
          },
          "leadSponsor": {
            "name": "Assiut University",
            "class": "OTHER"
          }
        },
        "oversightModule": {
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": false
        },
        "descriptionModule": {
          "briefSummary": "The aim of this study is to determine the accuracy and safety of SLNB after neoadjuvant chemotherapy.",
          "detailedDescription": "Breast cancer is the most common cancer among women. The morbidity and mortality of breast cancer are much higher than those observed with other female cancers . The incidence of breast cancer increases with age.\n\nApproximately 1.7 million new cases are estimated to occur worldwide, and mortality is increasing in developing countries, primarily because the disease is not diagnosed until it is in an advanced stage\n\nNeoadjuvant chemotherapy (NACT) is considered the standard of care for the anagement of locally advanced breast cancer and although this treatment has historically been reserved for those with inoperable breast cancer now is increasingly being used for women with earlier stage disease.\n\n. Encouraging results obtained with neoadjuvant chemotherapy in have resulted in clinicians using preoperative chemotherapy for patients with smaller tumors.\n\nNeoadjuvant chemotherapy (NACT) could reduce surgical morbidity of the breast and axilla. By down staging of the tumor, NACT can convert patients who are candidates for mastectomy to breast-conserving surgery (BCS) candidates .\n\nFurthermore, it has potential to reduce excision volumes in patients with large tumors who are already candidates for BCS. Another surgical advantage is down staging of the axilla so that axillary lymph node dissection can be avoided .\n\nIn the treatment of breast cancer, sentinel lymph node biopsy (SLNB) has replaced axillary lymph node dissection (ALND) as the staging procedure for patients with clinically node-negative disease. It provides accurate assessment of histological nodal status, guides additional therapies and is associated with less morbidity than ALND. Historically, patients who were clinically node-negative would undergo SLNB, whereas patients who were node-positive underwent ALND. SLNB in the neoadjuvant setting has become a topic of debate. Unfortunately, the reliability of SLNB after NAC remains questionable. Chemotherapy causes fibrosis, fat necrosis and granulation tissue formation, which alters lymphatic drainage patterns."
        },
        "conditionsModule": {
          "conditions": [
            "Sentinel Lymph Node"
          ]
        },
        "designModule": {
          "studyType": "INTERVENTIONAL",
          "phases": [
            "NA"
          ],
          "designInfo": {
            "allocation": "NA",
            "interventionModel": "SINGLE_GROUP",
            "interventionModelDescription": "female with breast cancer and malignant axillary lymphnodes who underwent neoadjuvant chemotherapy",
            "primaryPurpose": "TREATMENT",
            "maskingInfo": {
              "masking": "NONE"
            }
          },
          "enrollmentInfo": {
            "count": 30,
            "type": "ESTIMATED"
          }
        },
        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "female with breast cancer and positive axillary lymphnodes",
              "type": "OTHER",
              "description": "female patients with breast cancer with initially positive axillary lymphnodes who underwent neoadjuvant chemotherapy",
              "interventionNames": [
                "Procedure: sentinle lymphnode biopsy"
              ]
            }
          ],
          "interventions": [
            {
              "type": "PROCEDURE",
              "name": "sentinle lymphnode biopsy",
              "description": "intraoperative sentinle lymphnode biopsy",
              "armGroupLabels": [
                "female with breast cancer and positive axillary lymphnodes"
              ]
            }
          ]
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Sentinel Lymph Node Biopsy After Neoadjuvant Chemotherapy in Initially Node Positive Breast Cancer Patients, Could it Omit Axillary Dissection?",
              "description": "To evaluate the accuracy and safety of SLNB after neoadjuvant chemotherapy by 2 years follow up patients for recurrence clinically and radiologically by ultrasonography on axilla after one and two years .",
              "timeFrame": "Two year"
            }
          ]
        },
        "eligibilityModule": {
          "eligibilityCriteria": "Inclusion Criteria:\n\n1. Female patients with operable breast cancer who had node-positive disease at presentation and pathological confirmation with either FNA or core biopsy\n2. Female Patient aged from 18 to 60 years old\n3. Patients who are fit for general anesthesia.\n4. Patient who agree to provide short term outcome data and agree to provide contact information to provide contact information.\n\nExclusion Criteria:\n\n1. Stage 4 breast cancer\n2. Patient has no clinical response to NACT\n3. Patients who are contraindicated for radiotherapy\n4. Pregnant patients in first trimester\n5. Patient with inflammatory carcinoma",
          "healthyVolunteers": false,
          "sex": "FEMALE",
          "genderBased": true,
