nts": "{"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2024, 12/31/2024]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}"}}, {"id": "toolu_bdrk_01MsecutkgGDq7NSD4adzH8k", "type": "function", "function": {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "arguments": "{"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2025, 12/31/2025]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}"}}], "raw_parts": [{"type": "text", "text": "The studies are sorted in descending order (most recent first). I need to get studies from different years to analyze year-over-year trends. Let me use the advanced filter to get counts by different start date ranges to build a year-over-year enrollment trend. I'll query for specific year ranges to get the distribution."}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2020, 12/31/2020]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_01VC5PBoVtU8mArUYR8BENtW", "type": "tool_use"}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2021, 12/31/2021]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_018unqXwzDSD5MiDegBiBWrE", "type": "tool_use"}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2022, 12/31/2022]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_01GCLiH8xC2NhRfktRcwW6E7", "type": "tool_use"}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2023, 12/31/2023]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_01HBgUPVb8CE5pXFnaJ9g36x", "type": "tool_use"}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2024, 12/31/2024]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_01CiWmdQs4furfTZ9vVAisZJ", "type": "tool_use"}, {"name": "clinicaltrialsgov-mcp-server_clinicaltrials_list_studies", "input": {"countTotal": true, "filter": {"overallStatus": ["RECRUITING", "ACTIVE_NOT_RECRUITING"], "advanced": "AREA[StartDate]RANGE[01/01/2025, 12/31/2025]"}, "pageSize": 1, "query": {"cond": "breast cancer"}}, "id": "toolu_bdrk_01MsecutkgGDq7NSD4adzH8k", "type": "tool_use"}]}, {"role": "tool", "tool_call_id": "toolu_bdrk_01VC5PBoVtU8mArUYR8BENtW", "content": "{
  "totalCount": 215,
  "studies": [
    {
      "protocolSection": {
        "identificationModule": {
          "nctId": "NCT04520269",
          "orgStudyIdInfo": {
            "id": "MC02/04/19"
          },
          "organization": {
            "fullName": "National University Hospital, Singapore",
            "class": "OTHER"
          },
          "briefTitle": "A Single Arm, Phase Ib/II Trial of Single Agent Pacritinib in Patients With 1q21.3 Amplified Solid Tumors Enriching for Interleukin-1 Receptor-associated Kinase 1 Pathway Activation (PAIR)",
          "officialTitle": "A Single Arm, Phase Ib/II Trial of Single Agent Pacritinib in Patients With 1q21.3 Amplified Solid Tumors Enriching for Interleukin-1 Receptor-associated Kinase 1 (IRAK1) Pathway Activation (PAIR)"
        },
        "statusModule": {
          "statusVerifiedDate": "2025-09",
          "overallStatus": "ACTIVE_NOT_RECRUITING",
          "expandedAccessInfo": {
            "hasExpandedAccess": false
          },
          "startDateStruct": {
            "date": "2020-07-13",
            "type": "ACTUAL"
          },
          "primaryCompletionDateStruct": {
            "date": "2026-07",
            "type": "ESTIMATED"
          },
          "completionDateStruct": {
            "date": "2026-07",
            "type": "ESTIMATED"
          },
          "studyFirstSubmitDate": "2020-08-11",
          "studyFirstSubmitQcDate": "2020-08-17",
          "studyFirstPostDateStruct": {
            "date": "2020-08-20",
            "type": "ACTUAL"
          },
          "lastUpdateSubmitDate": "2025-09-22",
          "lastUpdatePostDateStruct": {
            "date": "2025-09-25",
            "type": "ACTUAL"
          }
        },
        "sponsorCollaboratorsModule": {
          "responsibleParty": {
            "type": "SPONSOR"
          },
          "leadSponsor": {
            "name": "National University Hospital, Singapore",
            "class": "OTHER"
          }
        },
        "oversightModule": {
          "oversightHasDmc": false,
          "isFdaRegulatedDrug": false,
          "isFdaRegulatedDevice": false
        },
        "descriptionModule": {
          "briefSummary": "This is a single arm, open-label, lead in phase Ib dose confirmation, followed by phase II study with 2 parallel study cohorts. Patients will be pre-screened for presence of 1q21.3 copy number amplification in plasma samples prior to screening process. Only patients with confirmed plasma cell-free DNA (cfDNA) 1q21.3 copy number amplification who successfully meet study eligibility criteria will be enrolled.\n\nThe phase Ib segment will be carried out in a standard 3+3 design, with a projected enrolment of 3 to 18 patients to determine the RP2D. In the phase II portion, 2 parallel cohorts will be enrolled (Cohort A: 1q21.3 amplified breast cancers, Cohort B: 1q21.3 amplified other solid tumors). Based on the Simon 2 stage optimal design, 12 patients will be enrolled in each cohort for stage I of the study, and assessed for PFS. If at least 3 of 12 patients meet study response criteria, the study will then be expanded to stage 2 to include a total of 25 patients in each cohort. Accounting for 10% attrition rate, a maximum of 28 patients will be enrolled into each cohort for phase II of the study.",
          "detailedDescription": "2.1. Hypothesis\n\n* Single agent pacritinib is effective in disease control of patients with 1q21.3 amplified solid tumors\n* Single agent pacritinib is safe in patients with 1q21.3 amplified solid tumors\n* Treatment with pacritinib will decrease plasma cfDNA copy number ratio of 1q21.3 in patients with 1q21.3 amplified solid tumors\n* Plasma cfDNA copy number ratio of 1q21.3 will correlate with serial radiological findings in patients with 1q21.3 amplified solid tumors\n\n2.2. Primary Objectives\n\n• To determine the proportion of patients with 1q21.3 amplified breast cancer (primary population: Cohort A) who remain progression-free at 4 months after treatment with pacritinib\n\n2.3. Secondary Objectives\n\n* To determine the safety and tolerability of pacritinib in patients with treatment refractory solid tumors\n* To determine the RP2D of pacritinib in patients with treatment refractory solid tumors\n* To evaluate disease response from pacritinib by RECIST criteria version 1.1 and tumor markers\n* To determine the proportion of patients with 1q21.3 amplified treatment refractory solid tumors excluding (exploratory population: Cohort B) who remain progression-free at 4 months after treatment with pacritinib\n\n2.4. Exploratory Objectives\n\n* To determine pharmacokinetic (PK) parameters including Cmax/min and steady state concentrations of pacritinib through serial plasma sampling\n* To determine pharmacodynamics (PD) parameters including highly sensitive C-reactive protein (CRP), HbA1c, changes in cytokine levels and plasma cfDNA levels of copy number ratio of 1q21.3\n* Correlation of plasma cfDNA levels of copy number ratio of 1q21.3 with radiological findings determined by RECIST criteria 1.1 and tumor markers"
        },
        "conditionsModule": {
          "conditions": [
            "Breast Cancer"
          ],
          "keywords": [
            "1q21.3",
            "interleukin-1 receptor-associated kinase 1",
            "Pacritinib",
            "IRAK1"
          ]
        },
        "designModule": {
          "studyType": "INTERVENTIONAL",
          "phases": [
            "PHASE1",
            "PHASE2"
          ],
          "designInfo": {
            "allocation": "NA",
            "interventionModel": "SINGLE_GROUP",
            "interventionModelDescription": "This is a single arm, open-label, lead in phase Ib dose confirmation, followed by phase II study with 2 parallel study cohorts.",
            "primaryPurpose": "TREATMENT",
            "maskingInfo": {
              "masking": "NONE"
            }
          },
          "enrollmentInfo": {
            "count": 74,
            "type": "ESTIMATED"
          }
        },
        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "Patient with (cfDNA) 1q21.3 copy number amplification",
              "type": "EXPERIMENTAL",
              "description": "The phase Ib segment will be carried out in a standard 3+3 design. In the phase II portion, 2 parallel cohorts will be enrolled (Cohort A: 1q21.3 amplified breast cancers, Cohort B: 1q21.3 amplified other solid tumors).",
              "interventionNames": [
                "Drug: Pacritinib"
              ]
            }
          ],
          "interventions": [
            {
              "type": "DRUG",
              "name": "Pacritinib",
              "description": "3+3 design Dose Level 1 :200mg BD every 4 weeks Dose Level -1 :200mg OM, 100mg ON every 4 weeks Dose Level -2 :100mg BD every 4 weeks",
              "armGroupLabels": [
                "Patient with (cfDNA) 1q21.3 copy number amplification"
              ]
            }
          ]
        },
        "outcomesModule": {
          "primaryOutcomes": [
            {
              "measure": "Overall radiological response rate",
              "description": "Rates of radiological response (complete and partial clinical response), including confidence intervals. measured by RECIST 1.1",
              "timeFrame": "36 months"
            },
            {
              "measure": "Progression-free survival",
              "description": "Proportion of patients in cohort A and Cohort B who remain progression-free at 4 months",
              "timeFrame": "36 months"
            },
            {
              "measure": "Overall safety of pacritinib in patients with treatment refractory solid tumors",
              "description": "Safety measures that will be used in the study include physical examinations and clinical laboratory tests (haematology and blood chemistries). Patients will be rated for toxicity during each cycle of treatment using the NCI CTCAE scale, version 4.03",
              "timeFrame": "36 months"
            }
          ]
        },
        "eligibilityModule": {
          "eligibilityCriteria": "Inclusion Criteria:\n\nPatients may be included in the study only if they meet all of the following criteria:\n\n* Age \\> or = 21 years.\n* Histological or cytological diagnosis of malignant advanced solid tumors refractory to standard therapy or for which no suitable effective standard therapy exists.\n\n  o Patients who fit above criteria will be pre-screened for presence of 1q21.3 amplification using a plasma assay based on digital PCR. Patients with tumors that exhibit 1q21.3amplification will be enrolled. Positive 1q21.3 amplification is defined as more than 3 standard deviations above the mean comparing the averaged copy number ratio of 3 genes (TUFT1, S100A8 and S100A7) relative to the reference gene RPP30 measure in sample (13).\n* ECOG 0-2\n* Has measureable or evaluable disease based on RECIST 1.1 criteria\n* Estimated life expectancy of at least 12 weeks.\n* Has documented progressive disease from last line of therapy\n* Has recovered from acute toxicities from prior anti-cancer therapies\n* Adequate organ function including the following:\n\n  * Bone marrow:\n\n    * Absolute neutrophil (segmented and bands) count (ANC) \\> or = 1.5 x 109/L\n    * Platelets \\> or = 100 x 109/L\n    * Hemoglobin \\> or = 8 x 109/L\n  * Hepatic:\n\n    * Bilirubin \\< or = 1.5 x upper limit of normal (ULN),\n    * ALT or AST \\< or = 2.5x ULN, (or \\< or = 5 X with liver metastases)\n  * Renal:\n\n    * Creatinine \\< or = 1.5x ULN\n* Signed informed consent from patient\n* Able to comply with study-related procedures.\n* Prior therapy (patients enrolled in phase Ib may be enrolled if they fulfil prior therapy criteria for either Cohort A or Cohort B)\n\n  * Cohort A only: Has received at least 2 lines of systemic therapy (endocrine or chemotherapy) in the palliative setting. Chemotherapy in an adjuvant setting for which patients relapsed within 6 months of completion can be considered as line(s) of palliative therapy.\n  * Cohort B only: Any number of prior lines of palliative chemotherapy.\n\nExclusion Criteria:\n\nPatients will be excluded from the study for any of the following reasons:\n\n* Treatment within the last 30 days with any investigational drug.\n* Concurrent administration of any other tumour therapy, including cytotoxic chemotherapy, hormonal therapy, and immunotherapy.\n* Major surgery within 28 days of study drug administration.\n* Active infection that in the opinion of the investigator would compromise the patient's ability to tolerate therapy.\n* Pregnancy.\n* Breast feeding.\n* Serious concomitant disorders that would compromise the safety of the patient or compromise the patient's ability to complete the study, at the discretion of the investigator.\n* Significant recent bleeding history defined as CTCAE grade 2 or higher within the past 3 months, unless precipitated by an inciting event (e.g. surgery, trauma, injury).\n* Suboptimal cardiac function, defined by:\n\n  * Any history of CTCAE grade \\> or = 2 non-dysrhythmia cardiac conditions within the last 6 months\n  * New York Heart Association class II, III or IV congestive cardiac failure\n  * Left ventricular ejection fraction of \\<45%\n* QTc prolongation of \\>450ms as assessed by ECG or other factors that increase the risk of QT interval prolongation\n* Second primary malignancy that is clinically detectable at the time of consideration for study enrollment.\n* Symptomatic brain metastasis.\n* History of significant neurological or mental disorder, including seizures or dementia.\n* Unable to comply with study procedures\n* Systemic treatment with a strong CYP3A4 inhibitor or storn CYP450 inducer within 14 days prior to treatment Day 1\n\nPhase Ib lead-in can recruit patients who fulfil critieria for either Cohort A or Cohort B AND all other inclusion/exclusion criteria",
          "healthyVolunteers": false,
          "sex": "ALL",
